// User represents the user record in the database (Entity/Model) type User struct { ID uint `gorm:"primaryKey;autoIncrement" json:"userId"` Username string `gorm:"type:varchar(100);not null" json:"username"` Email string `gorm:"type:varchar(100);uniqueIndex;not null" json:"email"` Password string `gorm:"type:varchar(255);not null" json:"-"` // Hide password when parse/marshal JSON Role string `gorm:"type:varchar(50);not null;default:'member'" json:"role"` // manager or member IsVerified bool `gorm:"not null;default:false" json:"isVerified"` CreatedAt time.Time `json:"createdAt"` UpdatedAt time.Time `json:"updatedAt"` DeletedAt gorm.DeletedAt `gorm:"index" json:"-"` }

const API_PREFIX = "/api/v1";

export class ApiError extends Error {
  constructor(message, status, details) {
    super(message);
    this.name = "ApiError";
    this.status = status;
    this.details = details;
  }
}

async function request(path, options = {}, token) {
  const headers = {
    "Content-Type": "application/json",
    ...(options.headers || {}),
  };

  if (token) {
    headers.Authorization = `Bearer ${token}`;
  }

  const response = await fetch(`${API_PREFIX}${path}`, {
    ...options,
    headers,
  });

  const isJSON = response.headers.get("content-type")?.includes("application/json");
  const body = isJSON ? await response.json() : null;

  if (!response.ok) {
    const message = body?.error || body?.message || `Request failed: ${response.status}`;
    throw new ApiError(message, response.status, body);
  }

  return body;
}

export default request;

const API_PREFIX = "/api/v1";

export class ApiError extends Error {
  constructor(message, status, details) {
    super(message);
    this.name = "ApiError";
    this.status = status;
    this.details = details;
  }
}

async function request(path, options = {}, token) {
  const headers = {
    "Content-Type": "application/json",
    ...(options.headers || {}),
  };

  if (options.body instanceof FormData) {
    delete headers["Content-Type"];
  }

  if (token) {
    headers.Authorization = `Bearer ${token}`;
  }

  const response = await fetch(`${API_PREFIX}${path}`, {
    ...options,
    headers,
  });

  const isJSON = response.headers.get("content-type")?.includes("application/json");
  const body = isJSON ? await response.json() : null;

  if (!response.ok) {
    const message = body?.error || body?.message || `Request failed: ${response.status}`;
    throw new ApiError(message, response.status, body);
  }

  return body;
}

export default request;

import request from "./apiClient";

export function registerApi(payload) {
  return request("/auth/register", {
    method: "POST",
    body: JSON.stringify(payload),
  });
}

export function verifyEmailApi(token) {
  const query = new URLSearchParams({ token });
  return request(`/auth/verify-email?${query.toString()}`, { method: "GET" });
}

