import { useState } from "react";
import { Link, useLocation, useNavigate } from "react-router-dom";
import { resendVerificationApi } from "../api/authApi";
import { useAuth } from "../context/AuthContext";
import { useToast } from "../context/ToastContext";
import { validateEmail, validatePassword } from "../utils/validators";

export default function LoginPage() {
  const navigate = useNavigate();
  const location = useLocation();
  const { login } = useAuth();
  const { pushToast } = useToast();

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [touched, setTouched] = useState({ email: false, password: false });
  const [error, setError] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [resending, setResending] = useState(false);

  const from = location.state?.from?.pathname;
  const emailError = validateEmail(email);
  const passwordError = validatePassword(password);
  const hasFieldErrors = Boolean(emailError || passwordError);

  const onSubmit = async (event) => {
    event.preventDefault();
    setTouched({ email: true, password: true });
    if (hasFieldErrors) {
      setError("Please fix form errors before submitting");
      return;
    }

    setError("");
    setSubmitting(true);

    try {
      const loginResult = await login({ email, password });
      pushToast("Login successful", "success");
      const defaultPath = loginResult?.user?.role === "manager" ? "/users" : "/profile";
      const nextPath = from && from !== "/login" ? from : defaultPath;
      navigate(nextPath, { replace: true });
    } catch (err) {
      setError(err.message);
      pushToast(err.message, "error");
    } finally {
      setSubmitting(false);
    }
  };

  const onResendVerification = async () => {
    setTouched((prev) => ({ ...prev, email: true }));
    if (emailError) {
      setError("Enter a valid email before resending verification");
      return;
    }

    setResending(true);
    try {
      const response = await resendVerificationApi({ email });
      pushToast(response?.message || "Verification email sent", "success");
    } catch (err) {
      pushToast(err.message, "error");
    } finally {
      setResending(false);
    }
  };

  const shouldShowResend = error.toLowerCase().includes("not verified");

  return (
    <section className="auth-layout">
      <aside className="auth-hero">
        <p className="auth-kicker">Identity Access</p>
        <h2>Welcome Back</h2>
        <p>
          Sign in to access your profile, verify your account status, and continue team management workflows.
        </p>
      </aside>

      <section className="card auth-card">
        <h2>Login</h2>
        <p className="muted page-lead">Use your registered email and password.</p>
        <form className="form-grid" onSubmit={onSubmit}>
          <input
            type="email"
            placeholder="Email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            onBlur={() => setTouched((prev) => ({ ...prev, email: true }))}
            className={touched.email && emailError ? "input-error" : ""}
            required
          />
          {touched.email && emailError && <p className="field-error">{emailError}</p>}
          <input
            type="password"
            placeholder="Password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            onBlur={() => setTouched((prev) => ({ ...prev, password: true }))}
            className={touched.password && passwordError ? "input-error" : ""}
            required
          />
          {touched.password && passwordError && <p className="field-error">{passwordError}</p>}
          <button className="primary" type="submit" disabled={submitting || hasFieldErrors}>
            {submitting ? "Logging in..." : "Login"}
          </button>
        </form>
        {error && <p className="error">{error}</p>}
        {shouldShowResend && (
          <button className="primary" type="button" onClick={onResendVerification} disabled={resending}>
            {resending ? "Sending..." : "Resend verification email"}
          </button>
        )}
        <p className="muted auth-switch">
          No account yet? <Link to="/register">Register here</Link>
        </p>
      </section>
    </section>
  );
}

import { useState } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import { resendVerificationApi } from "../api/authApi";
import { useAuth } from "../context/AuthContext";
import { useToast } from "../context/ToastContext";
import { validateEmail, validatePassword } from "../utils/validators";
import { GoogleLogin } from "@react-oauth/google";

export default function LoginPage() {
  const navigate = useNavigate();
  const location = useLocation();
  const { login, googleLogin } = useAuth();
  const { pushToast } = useToast();

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [touched, setTouched] = useState({ email: false, password: false });
  const [error, setError] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [resending, setResending] = useState(false);

  const from = location.state?.from?.pathname;
  const emailError = validateEmail(email);
  const passwordError = validatePassword(password);
  const hasFieldErrors = Boolean(emailError || passwordError);

  const onSubmit = async (event) => {
    event.preventDefault();
    setTouched({ email: true, password: true });
    if (hasFieldErrors) {
      setError("Please fix form errors before submitting");
      return;
    }

    setError("");
    setSubmitting(true);

    try {
      const loginResult = await login({ email, password });
      pushToast("Login successful", "success");
      const defaultPath = loginResult?.user?.role === "manager" ? "/users" : "/profile";
      const nextPath = from && from !== "/login" ? from : defaultPath;
      navigate(nextPath, { replace: true });
    } catch (err) {
      setError(err.message);
      pushToast(err.message, "error");
    } finally {
      setSubmitting(false);
    }
  };

  const onResendVerification = async () => {
    setTouched((prev) => ({ ...prev, email: true }));
    if (emailError) {
      setError("Enter a valid email before resending verification");
      return;
    }

    setResending(true);
    try {
      const response = await resendVerificationApi({ email });
      pushToast(response?.message || "Verification email sent", "success");
    } catch (err) {
      pushToast(err.message, "error");
    } finally {
      setResending(false);
    }
  };

  const shouldShowResend = error.toLowerCase().includes("not verified");

  const handleGoogleSuccess = async (credentialResponse) => {
    setError("");
    setSubmitting(true);
    try {
      await googleLogin(credentialResponse.credential);
      navigate("/profile");
    } catch (err) {
      setError(err.message || "Google login failed.");
      setSubmitting(false);
    }
  };

  return (
    <section className="auth-layout">
      <aside className="auth-hero">
        <p className="auth-kicker">Identity Access</p>
        <h2>Welcome Back</h2>
        <p>
          Sign in to access your profile, verify your account status, and continue team management workflows.
        </p>
      </aside>

      <section className="card auth-card">
        <h2>Login</h2>
        <p className="muted page-lead">Use your registered email and password.</p>
        <form className="form-grid" onSubmit={onSubmit}>
          <input
            type="email"
            placeholder="Email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            onBlur={() => setTouched((prev) => ({ ...prev, email: true }))}
            className={touched.email && emailError ? "input-error" : ""}
            required
          />
          {touched.email && emailError && <p className="field-error">{emailError}</p>}
          <input
            type="password"
            placeholder="Password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            onBlur={() => setTouched((prev) => ({ ...prev, password: true }))}
            className={touched.password && passwordError ? "input-error" : ""}
            required
          />
          {touched.password && passwordError && <p className="field-error">{passwordError}</p>}
          <button className="primary" type="submit" disabled={submitting || hasFieldErrors}>
            {submitting ? "Logging in..." : "Login"}
          </button>
        </form>
        {error && <p className="error">{error}</p>}
        {shouldShowResend && (
          <button className="primary" type="button" onClick={onResendVerification} disabled={resending}>
            {resending ? "Sending..." : "Resend verification email"}
          </button>
        )}
        <p className="muted auth-switch">
          No account yet? <Link to="/register">Register here</Link>
        </p>
        <div style={{ marginTop: "2rem", display: "flex", justifyContent: "center" }}>
          <GoogleLogin
            onSuccess={handleGoogleSuccess}
            onError={() => setError("Google Setup/Login Failed")}
            theme="filled_blue"
            shape="pill"
            text="signin_with"
          />
        </div>
      </section>
    </section>
  );
}

import { useEffect, useState } from "react";
import { listUsersApi } from "../api/userApi";
import { useAuth } from "../context/AuthContext";

export default function UsersPage() {
  const { token } = useAuth();
  const [users, setUsers] = useState([]);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let active = true;

    async function loadUsers() {
      try {
        const data = await listUsersApi(token, 1, 50);
        if (active) {
          setUsers(data.data || []);
        }
      } catch (err) {
        if (active) {
          setError(err.message);
        }
      } finally {
        if (active) {
          setLoading(false);
        }
      }
    }

    loadUsers();
    return () => {
      active = false;
    };
  }, [token]);

  if (loading) {
    return (
      <section className="card page-panel users-panel" style={{ display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        <div style={{ color: 'var(--text-muted)', fontSize: '1.1rem' }}>
          <div className="spinner"></div> Loading workspace users...
        </div>
      </section>
    );
  }

  return (
    <section className="card page-panel users-panel">
      <div style={{ marginBottom: '2.5rem' }}>
        <h2 style={{ marginBottom: '0.5rem' }}>Users Directory</h2>
        <p className="muted" style={{ margin: 0 }}>Manager override: Viewing all workspace accounts and access levels.</p>
      </div>

      {error && <p className="error">{error}</p>}
      {!error && (
        <div className="table-wrap">
          <table className="table">
            <thead>
              <tr>
                <th>Member ID</th>
                <th>Username</th>
                <th>Contact Email</th>
                <th>Access Level</th>
              </tr>
            </thead>
            <tbody>
              {users.map((u) => (
                <tr key={u.userId}>
                  <td style={{ opacity: 0.6, fontFamily: 'monospace' }}>#{u.userId}</td>
                  <td style={{ fontWeight: '500', color: '#fff' }}>{u.username}</td>
                  <td className="muted">{u.email}</td>
                  <td>
                    <span className={`badge badge-${u.role}`}>
                      {u.role}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </section>
  );
}

import { useEffect, useState } from "react";
import { listUsersApi } from "../api/userApi";
import { useAuth } from "../context/AuthContext";
import ImportUsersModal from "../components/ImportUsersModal";

export default function UsersPage() {
  const { token, user } = useAuth();
  const [users, setUsers] = useState([]);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(true);
  const [showImport, setShowImport] = useState(false);

  const loadUsers = async () => {
    try {
      setLoading(true);
      const data = await listUsersApi(token, 1, 50);
      setUsers(data.data || []);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    let active = true;

    async function initialLoad() {
      try {
        const data = await listUsersApi(token, 1, 50);
        if (active) {
          setUsers(data.data || []);
        }
      } catch (err) {
        if (active) {
          setError(err.message);
        }
      } finally {
        if (active) {
          setLoading(false);
        }
      }
    }

    initialLoad();
    return () => {
      active = false;
    };
  }, [token]);

  if (loading && users.length === 0) {
    return (
      <section className="card page-panel users-panel" style={{ display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        <div style={{ color: 'var(--text-muted)', fontSize: '1.1rem' }}>
          <div className="spinner"></div> Loading workspace users...
        </div>
      </section>
    );
  }

  return (
    <section className="card page-panel users-panel">
      <div style={{ marginBottom: '2.5rem', display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
        <div>
          <h2 style={{ marginBottom: '0.5rem' }}>Users Directory</h2>
          <p className="muted" style={{ margin: 0 }}>Manager override: Viewing all workspace accounts and access levels.</p>
        </div>
        {user?.role === "manager" && (
          <button className="nav-btn" onClick={() => setShowImport(true)}>
            Bulk Import CSV
          </button>
        )}
      </div>
      
      {error && <p className="error">{error}</p>}
      {!error && (
        <div className="table-wrap">
          <table className="table">
            <thead>
              <tr>
                <th>Member ID</th>
                <th>Username</th>
                <th>Contact Email</th>
                <th>Access Level</th>
              </tr>
            </thead>
            <tbody>
              {users.map((u) => (
                <tr key={u.userId}>
                  <td style={{ opacity: 0.6, fontFamily: 'monospace' }}>#{u.userId}</td>
                  <td style={{ fontWeight: '500', color: '#fff' }}>{u.username}</td>
                  <td className="muted">{u.email}</td>
                  <td>
                    <span className={`badge badge-${u.role}`}>
                      {u.role}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {showImport && (
        <ImportUsersModal 
          token={token} 
          onClose={() => setShowImport(false)} 
          onImportSuccess={() => loadUsers()} 
        />
      )}
    </section>
  );
}

