func (u *authUsecaseImpl) issueVerification(user *domain.User) error {
	if !isSMTPConfigured(u.smtpConfig) {
		return ErrSMTPNotConfigured
	}

	if err := u.verifyRepo.PurgeExpired(time.Now()); err != nil {
		return err
	}

	if err := u.verifyRepo.DeleteActiveTokensByUserID(user.ID); err != nil {
		return err
	}

	rawToken := uuid.NewString()
	tokenHash := hashToken(rawToken)
	expiresAt := time.Now().Add(u.verifyTokenTTL)

	verificationToken := &domain.EmailVerificationToken{
		UserID:    user.ID,
		TokenHash: tokenHash,
		ExpiresAt: expiresAt,
	}

	if err := u.verifyRepo.CreateToken(verificationToken); err != nil {
		return err
	}

	verifyURL := fmt.Sprintf("%s/api/v1/auth/verify-email?token=%s", u.appBaseURL, rawToken)
	if err := utils.SendVerificationEmail(u.smtpConfig, user.Email, verifyURL); err != nil {
		return err
	}

	return nil
}

func toUserResponse(user *domain.User) UserResponse {
	return UserResponse{
		ID:         user.ID,
		Username:   user.Username,
		Email:      user.Email,
		Role:       user.Role,
		IsVerified: user.IsVerified,
		CreatedAt:  user.CreatedAt,
		UpdatedAt:  user.UpdatedAt,
	}
}

func hashToken(rawToken string) string {
	sum := sha256.Sum256([]byte(strings.TrimSpace(rawToken)))
	return hex.EncodeToString(sum[:])
}

func readIntEnvWithDefault(key string, fallback int) int {
	value := strings.TrimSpace(os.Getenv(key))
	if value == "" {
		return fallback
	}

	parsed, err := strconv.Atoi(value)
	if err != nil || parsed <= 0 {
		return fallback
	}
	return parsed
}

func isSMTPConfigured(cfg utils.SMTPConfig) bool {
	return cfg.Host != "" && cfg.Username != "" && cfg.Password != ""
}

package utils

import (
	"encoding/json"
	"fmt"
	"net/http"
	"time"
)

type TokenInfoResponse struct {
	Aud           string `json:"aud"`
	Sub           string `json:"sub"`
	Email         string `json:"email"`
	EmailVerified string `json:"email_verified"`
	Name          string `json:"name"`
	Picture       string `json:"picture"`
	GivenName     string `json:"given_name"`
	FamilyName    string `json:"family_name"`
	Error         string `json:"error"`
	ErrorDesc     string `json:"error_description"`
}

func VerifyGoogleIDToken(idToken string) (*TokenInfoResponse, error) {
	url := fmt.Sprintf("https://oauth2.googleapis.com/tokeninfo?id_token=%s", idToken)

	client := &http.Client{Timeout: 5 * time.Second}
	resp, err := client.Get(url)
	if err != nil {
		return nil, fmt.Errorf("failed to make request to google: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("invalid token, status code: %d", resp.StatusCode)
	}

	var tokenInfo TokenInfoResponse
	if err := json.NewDecoder(resp.Body).Decode(&tokenInfo); err != nil {
		return nil, fmt.Errorf("failed to decode response: %w", err)
	}

	if tokenInfo.Error != "" {
		return nil, fmt.Errorf("google error: %s", tokenInfo.ErrorDesc)
	}

	return &tokenInfo, nil
}

package domain

// UserRef is a read-only mapping to auth service users table.
type UserRef struct {
	ID   uint   `gorm:"column:id;primaryKey"`
	Role string `gorm:"column:role"`
}

func (UserRef) TableName() string {
	return "users"
}

package repository

import (
	"team-management-service/internal/domain"

	"gorm.io/gorm"
)

// UserRepository provides read-only access to global user records.
type UserRepository interface {
	FindByID(id uint) (*domain.UserRef, error)
}

type userRepositoryImpl struct {
	db *gorm.DB
}

func NewUserRepository(db *gorm.DB) UserRepository {
	return &userRepositoryImpl{db: db}
}

func (r *userRepositoryImpl) FindByID(id uint) (*domain.UserRef, error) {
	var user domain.UserRef
	err := r.db.First(&user, id).Error
	if err != nil {
		return nil, err
	}
	return &user, nil
}
